namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Forklift A",        "Warehouse 1", new DateTime(2026, 3, 15)),
            new(2, "Conveyor Belt B",   "Warehouse 2", new DateTime(2026, 4, 22)),
            new(3, "Drill Press C",     "Shop Floor",  new DateTime(2026, 1, 10)),
            new(4, "Lathe D",           "Shop Floor",  new DateTime(2025, 12, 5)),
            new(5, "Crane E",           "Yard",        new DateTime(2026, 5, 1)),
            new(6, "Compressor F",      "Utility Room",new DateTime(2026, 2, 18)),
            new(7, "Welding Station G", "Shop Floor",  new DateTime(2026, 4, 30)),
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@attribute [StreamRendering]
@using InventoryApp.Services
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _equipment;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            // Interactive reconnect: use persisted data instead of fetching again
            _equipment = restored;
        }
        else
        {
            // First render (prerender): fetch from service
            _equipment = await EquipmentSvc.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("equipment", _equipment);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

